using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Data.Models;

namespace VetClinic.Services;

public class BillingService(ApplicationDbContext db)
{
    public async Task<List<Invoice>> GetInvoicesAsync(InvoiceStatus? status = null)
    {
        var query = db.Invoices
            .Include(i => i.Owner)
            .Include(i => i.LineItems)
            .Include(i => i.Payments)
            .AsQueryable();
        if (status.HasValue)
            query = query.Where(i => i.Status == status.Value);
        return await query.OrderByDescending(i => i.CreatedAt).ToListAsync();
    }

    public async Task<Invoice?> GetInvoiceAsync(int id) =>
        await db.Invoices
            .Include(i => i.Owner)
            .Include(i => i.LineItems)
            .Include(i => i.Payments)
            .Include(i => i.Appointment)
            .FirstOrDefaultAsync(i => i.Id == id);

    public async Task SaveInvoiceAsync(Invoice invoice)
    {
        if (invoice.Id == 0) db.Invoices.Add(invoice);
        else db.Invoices.Update(invoice);
        await db.SaveChangesAsync();
    }

    public async Task AddLineItemAsync(int invoiceId, string description, decimal amount)
    {
        var item = new InvoiceLineItem { InvoiceId = invoiceId, Description = description, Amount = amount };
        db.InvoiceLineItems.Add(item);
        await db.SaveChangesAsync();
    }

    public async Task RemoveLineItemAsync(int lineItemId)
    {
        var item = await db.InvoiceLineItems.FindAsync(lineItemId);
        if (item != null) { db.InvoiceLineItems.Remove(item); await db.SaveChangesAsync(); }
    }

    public async Task ProcessPaymentAsync(int invoiceId, decimal amount, PaymentMethod method, string? reference = null)
    {
        var invoice = await db.Invoices.Include(i => i.LineItems).Include(i => i.Payments).FirstAsync(i => i.Id == invoiceId);
        var payment = new Payment { InvoiceId = invoiceId, Amount = amount, Method = method, Reference = reference };
        db.Payments.Add(payment);

        if (invoice.AmountPaid + amount >= invoice.Total)
            invoice.Status = InvoiceStatus.Paid;

        await db.SaveChangesAsync();
    }

    public async Task<List<Payment>> GetPaymentHistoryAsync(int? ownerId = null)
    {
        var query = db.Payments.Include(p => p.Invoice).ThenInclude(i => i.Owner).AsQueryable();
        if (ownerId.HasValue)
            query = query.Where(p => p.Invoice.OwnerId == ownerId.Value);
        return await query.OrderByDescending(p => p.PaidAt).ToListAsync();
    }
}

