using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Data.Models;

namespace VetClinic.Services;

public class AppointmentService(ApplicationDbContext db)
{
    public async Task<List<Appointment>> GetAppointmentsAsync(DateTime from, DateTime to)
    {
        return await db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime >= from && a.StartTime < to && a.Status != AppointmentStatus.Cancelled)
            .OrderBy(a => a.StartTime)
            .ToListAsync();
    }

    public async Task<Appointment?> GetAppointmentAsync(int id) =>
        await db.Appointments.Include(a => a.Pet).ThenInclude(p => p.Owner)
            .FirstOrDefaultAsync(a => a.Id == id);

    public async Task SaveAppointmentAsync(Appointment appointment)
    {
        if (appointment.Id == 0) db.Appointments.Add(appointment);
        else db.Appointments.Update(appointment);
        await db.SaveChangesAsync();
    }

    public async Task CancelAppointmentAsync(int id)
    {
        var appt = await db.Appointments.FindAsync(id);
        if (appt != null)
        {
            appt.Status = AppointmentStatus.Cancelled;
            await db.SaveChangesAsync();
        }
    }

    public async Task<List<TimeSlot>> GetAvailableSlotsAsync(DateOnly date, int durationMinutes = 30)
    {
        var dayStart = date.ToDateTime(new TimeOnly(8, 0));
        var dayEnd = date.ToDateTime(new TimeOnly(18, 0));

        var existing = await db.Appointments
            .Where(a => a.StartTime >= dayStart && a.StartTime < dayEnd && a.Status == AppointmentStatus.Scheduled)
            .OrderBy(a => a.StartTime)
            .ToListAsync();

        var slots = new List<TimeSlot>();
        var current = dayStart;
        while (current.AddMinutes(durationMinutes) <= dayEnd)
        {
            var end = current.AddMinutes(durationMinutes);
            var isAvailable = !existing.Any(a => a.StartTime < end && a.EndTime > current);
            slots.Add(new TimeSlot(current, end, isAvailable));
            current = current.AddMinutes(durationMinutes);
        }
        return slots;
    }
}

public record TimeSlot(DateTime Start, DateTime End, bool IsAvailable);

