+using Microsoft.EntityFrameworkCore;
+using VetClinic.Data;
+using VetClinic.Data.Models;
+
+namespace VetClinic.Services;
+
+public class BillingService(ApplicationDbContext db)
+{
+    public async Task<List<Invoice>> GetInvoicesAsync(InvoiceStatus? status = null)
+    {
+        var query = db.Invoices
+            .Include(i => i.Owner)
+            .Include(i => i.LineItems)
+            .Include(i => i.Payments)
+            .AsQueryable();
+        if (status.HasValue)
+            query = query.Where(i => i.Status == status.Value);
+        return await query.OrderByDescending(i => i.CreatedAt).ToListAsync();
+    }
+
+    public async Task<Invoice?> GetInvoiceAsync(int id) =>
+        await db.Invoices
+            .Include(i => i.Owner)
+            .Include(i => i.LineItems)
+            .Include(i => i.Payments)
+            .Include(i => i.Appointment)
+            .FirstOrDefaultAsync(i => i.Id == id);
+
+    public async Task SaveInvoiceAsync(Invoice invoice)
+    {
+        if (invoice.Id == 0) db.Invoices.Add(invoice);
+        else db.Invoices.Update(invoice);
+        await db.SaveChangesAsync();
+    }
+
+    public async Task AddLineItemAsync(int invoiceId, string description, decimal amount)
+    {
+        var item = new InvoiceLineItem { InvoiceId = invoiceId, Description = description, Amount = amount };
