﻿@page "/"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject VetClinic.Services.AppointmentService AppointmentSvc
@inject VetClinic.Services.BillingService BillingSvc

<PageTitle>VetClinic - Dashboard</PageTitle>

<h1>Dashboard</h1>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Today's Appointments</h5>
                <p class="card-text display-4">@todayCount</p>
                <a href="appointments" class="btn btn-primary">View Schedule</a>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Pending Invoices</h5>
                <p class="card-text display-4">@pendingInvoices</p>
                <a href="billing" class="btn btn-primary">View Billing</a>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Quick Actions</h5>
                <a href="patients/new" class="btn btn-outline-primary d-block mb-2">Register Patient</a>
                <a href="appointments/new" class="btn btn-outline-primary d-block">New Appointment</a>
            </div>
        </div>
    </div>
</div>

@if (todayAppointments.Any())
{
    <h3 class="mt-4">Today's Schedule</h3>
    <table class="table table-striped">
        <thead>
            <tr><th>Time</th><th>Pet</th><th>Owner</th><th>Reason</th><th>Status</th></tr>
        </thead>
        <tbody>
            @foreach (var appt in todayAppointments)
            {
                <tr>
                    <td>@appt.StartTime.ToString("HH:mm")</td>
                    <td>@appt.Pet.Name</td>
                    <td>@appt.Pet.Owner.FullName</td>
                    <td>@appt.Reason</td>
                    <td><span class="badge bg-info">@appt.Status</span></td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private int todayCount;
    private int pendingInvoices;
    private List<VetClinic.Data.Models.Appointment> todayAppointments = [];

    protected override async Task OnInitializedAsync()
    {
        var today = DateTime.Today;
        todayAppointments = await AppointmentSvc.GetAppointmentsAsync(today, today.AddDays(1));
        todayCount = todayAppointments.Count;
        var pending = await BillingSvc.GetInvoicesAsync(VetClinic.Data.Models.InvoiceStatus.Pending);
        pendingInvoices = pending.Count;
    }
}

