@page "/appointments"
@page "/appointments/new"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject VetClinic.Services.AppointmentService AppointmentSvc
@inject VetClinic.Services.PatientService PatientSvc

<PageTitle>Appointments</PageTitle>

<h1>Appointments</h1>

<div class="row">
    <div class="col-md-8">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <button class="btn btn-outline-secondary" @onclick="PrevWeek">&lt; Prev</button>
            <h4>@weekStart.ToString("MMM d") — @weekStart.AddDays(6).ToString("MMM d, yyyy")</h4>
            <button class="btn btn-outline-secondary" @onclick="NextWeek">Next &gt;</button>
        </div>

        <div class="table-responsive">
            <table class="table table-bordered table-sm">
                <thead>
                    <tr>
                        <th>Time</th>
                        @for (int d = 0; d < 7; d++)
                        {
                            var day = weekStart.AddDays(d);
                            <th class="@(day.Date == DateTime.Today ? "table-primary" : "")">@day.ToString("ddd M/d")</th>
                        }
                    </tr>
                </thead>
                <tbody>
                    @for (int hour = 8; hour < 18; hour++)
                    {
                        <tr>
                            <td><strong>@($"{hour:D2}:00")</strong></td>
                            @for (int d = 0; d < 7; d++)
                            {
                                var slotTime = weekStart.AddDays(d).AddHours(hour);
                                var appt = weekAppointments.FirstOrDefault(a => a.StartTime <= slotTime && a.EndTime > slotTime);
                                if (appt != null)
                                {
                                    <td class="table-info" style="cursor:pointer" @onclick="() => EditAppointment(appt)">
                                        <small>@appt.Pet.Name - @appt.Reason</small>
                                    </td>
                                }
                                else
                                {
                                    <td style="cursor:pointer" @onclick="() => SelectSlot(slotTime)">
                                        <small class="text-success">Available</small>
                                    </td>
                                }
                            }
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-header">
                @if (editingAppointment.Id > 0) { <text>Edit Appointment</text> }
                else { <text>New Appointment</text> }
            </div>
            <div class="card-body">
                <EditForm Model="editingAppointment" OnValidSubmit="SaveAsync" FormName="apptForm">
                    <DataAnnotationsValidator />
                    <ValidationSummary />

                    <div class="mb-2">
                        <label class="form-label">Pet</label>
                        <InputSelect class="form-control" @bind-Value="editingAppointment.PetId">
                            <option value="0">-- Select Pet --</option>
                            @foreach (var pet in allPets)
                            {
                                <option value="@pet.Id">@pet.Name (@pet.Owner.FullName)</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Date & Time</label>
                        <InputDate class="form-control" Type="InputDateType.DateTimeLocal" @bind-Value="editingAppointment.StartTime" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Duration (min)</label>
                        <InputNumber class="form-control" @bind-Value="durationMinutes" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Reason</label>
                        <InputText class="form-control" @bind-Value="editingAppointment.Reason" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Veterinarian</label>
                        <InputText class="form-control" @bind-Value="editingAppointment.Veterinarian" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Notes</label>
                        <InputTextArea class="form-control" rows="2" @bind-Value="editingAppointment.Notes" />
                    </div>

                    <button type="submit" class="btn btn-primary">Save</button>
                    @if (editingAppointment.Id > 0)
                    {
                        <button type="button" class="btn btn-danger ms-2" @onclick="CancelAppointment">Cancel Appt</button>
                    }
                    <button type="button" class="btn btn-secondary ms-2" @onclick="ResetForm">Clear</button>
                </EditForm>
            </div>
        </div>
    </div>
</div>

@code {
    private DateTime weekStart = DateTime.Today.AddDays(-(int)DateTime.Today.DayOfWeek);
    private List<VetClinic.Data.Models.Appointment> weekAppointments = [];
    private List<VetClinic.Data.Models.Pet> allPets = [];
    private VetClinic.Data.Models.Appointment editingAppointment = new() { StartTime = DateTime.Today.AddHours(9) };
    private int durationMinutes = 30;

    protected override async Task OnInitializedAsync()
    {
        allPets = await PatientSvc.SearchPetsAsync();
        await LoadWeekAsync();
    }

    private async Task LoadWeekAsync()
    {
        weekAppointments = await AppointmentSvc.GetAppointmentsAsync(weekStart, weekStart.AddDays(7));
    }

    private async Task PrevWeek() { weekStart = weekStart.AddDays(-7); await LoadWeekAsync(); }
    private async Task NextWeek() { weekStart = weekStart.AddDays(7); await LoadWeekAsync(); }

    private void SelectSlot(DateTime time)
    {
        editingAppointment = new VetClinic.Data.Models.Appointment { StartTime = time };
    }

    private void EditAppointment(VetClinic.Data.Models.Appointment appt)
    {
        editingAppointment = appt;
        durationMinutes = (int)(appt.EndTime - appt.StartTime).TotalMinutes;
    }

    private async Task SaveAsync()
    {
        editingAppointment.EndTime = editingAppointment.StartTime.AddMinutes(durationMinutes);
        await AppointmentSvc.SaveAppointmentAsync(editingAppointment);
        ResetForm();
        await LoadWeekAsync();
    }

    private async Task CancelAppointment()
    {
        if (editingAppointment.Id > 0)
        {
            await AppointmentSvc.CancelAppointmentAsync(editingAppointment.Id);
            ResetForm();
            await LoadWeekAsync();
        }
    }

    private void ResetForm()
    {
        editingAppointment = new VetClinic.Data.Models.Appointment { StartTime = DateTime.Today.AddHours(9) };
        durationMinutes = 30;
    }
}

