@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject VetClinic.Services.BillingService BillingSvc
@inject VetClinic.Services.PatientService PatientSvc
@inject NavigationManager Nav

<PageTitle>Billing</PageTitle>

<h1>Billing</h1>

<div class="row mb-3">
    <div class="col-md-4">
        <select class="form-select" @onchange="FilterChanged">
            <option value="">All Invoices</option>
            <option value="Pending">Pending</option>
            <option value="Paid">Paid</option>
            <option value="Overdue">Overdue</option>
        </select>
    </div>
    <div class="col-md-8 text-end">
        <a href="billing/new" class="btn btn-primary">New Invoice</a>
    </div>
</div>

@if (invoices is null)
{
    <p>Loading...</p>
}
else
{
    <table class="table table-hover">
        <thead>
            <tr><th>#</th><th>Date</th><th>Owner</th><th>Total</th><th>Paid</th><th>Balance</th><th>Status</th><th></th></tr>
        </thead>
        <tbody>
            @foreach (var inv in invoices)
            {
                <tr>
                    <td>@inv.Id</td>
                    <td>@inv.CreatedAt.ToString("d")</td>
                    <td>@inv.Owner.FullName</td>
                    <td>@inv.Total.ToString("C")</td>
                    <td>@inv.AmountPaid.ToString("C")</td>
                    <td>@inv.Balance.ToString("C")</td>
                    <td>
                        <span class="badge @StatusBadge(inv.Status)">@inv.Status</span>
                    </td>
                    <td>
                        <a href="billing/@inv.Id" class="btn btn-sm btn-outline-primary">Details</a>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

<hr />
<h3>Payment History</h3>
@if (payments is null)
{
    <p>Loading...</p>
}
else if (!payments.Any())
{
    <p class="text-muted">No payments recorded.</p>
}
else
{
    <table class="table table-sm">
        <thead>
            <tr><th>Date</th><th>Invoice #</th><th>Owner</th><th>Amount</th><th>Method</th><th>Reference</th></tr>
        </thead>
        <tbody>
            @foreach (var p in payments.Take(20))
            {
                <tr>
                    <td>@p.PaidAt.ToString("g")</td>
                    <td>@p.InvoiceId</td>
                    <td>@p.Invoice.Owner.FullName</td>
                    <td>@p.Amount.ToString("C")</td>
                    <td>@p.Method</td>
                    <td>@p.Reference</td>
                </tr>
            }
        </tbody>
    </table>
}

