    protected override async Task OnInitializedAsync()
    {
        await LoadAsync();
    }

    private async Task LoadAsync()
    {
        invoices = await BillingSvc.GetInvoicesAsync(statusFilter);
        payments = await BillingSvc.GetPaymentHistoryAsync();
    }

