@page "/billing/{InvoiceId:int}"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject VetClinic.Services.BillingService BillingSvc
@inject VetClinic.Services.PatientService PatientSvc
@inject NavigationManager Nav

<PageTitle>@(InvoiceId.HasValue ? $"Invoice #{InvoiceId}" : "New Invoice")</PageTitle>

<h1>@(InvoiceId.HasValue ? $"Invoice #{InvoiceId}" : "New Invoice")</h1>

@if (!InvoiceId.HasValue)
{
    <EditForm Model="invoice" OnValidSubmit="CreateInvoiceAsync" FormName="invoiceCreateForm">
        <DataAnnotationsValidator />
        <div class="row mb-3">
            <div class="col-md-6">
                <label class="form-label">Owner</label>
                <InputSelect class="form-control" @bind-Value="invoice.OwnerId">
                    <option value="0">-- Select Owner --</option>
                    @foreach (var owner in owners)
                    {
                        <option value="@owner.Id">@owner.FullName</option>
                    }
                </InputSelect>
            </div>
            <div class="col-md-6">
                <label class="form-label">Due Date</label>
                <InputDate class="form-control" @bind-Value="invoice.DueDate" />
            </div>
        </div>
        <button type="submit" class="btn btn-primary">Create Invoice</button>
        <a href="billing" class="btn btn-secondary ms-2">Cancel</a>
    </EditForm>
}
else if (invoice.Id > 0)
{
    <div class="row">
        <div class="col-md-8">
            <div class="card mb-3">
                <div class="card-header d-flex justify-content-between">
                    <span>Owner: <strong>@invoice.Owner?.FullName</strong></span>
                    <span class="badge @StatusBadge(invoice.Status)">@invoice.Status</span>
                </div>
                <div class="card-body">
                    <p>Created: @invoice.CreatedAt.ToString("g") | Due: @invoice.DueDate?.ToString("d")</p>

                    <h5>Line Items</h5>
                    <table class="table table-sm">
                        <thead><tr><th>Description</th><th>Amount</th><th></th></tr></thead>
                        <tbody>
                            @foreach (var item in invoice.LineItems)
                            {
                                <tr>
                                    <td>@item.Description</td>
                                    <td>@item.Amount.ToString("C")</td>
                                    <td><button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveItemAsync(item.Id)">Remove</button></td>
                                </tr>
                            }
                        </tbody>
                        <tfoot>
                            <tr><th>Total</th><th>@invoice.Total.ToString("C")</th><th></th></tr>
                        </tfoot>
                    </table>

                    <div class="row g-2 align-items-end">
                        <div class="col-md-6">
                            <input class="form-control" placeholder="Description" @bind="newItemDescription" />
                        </div>
                        <div class="col-md-3">
                            <input type="number" step="0.01" class="form-control" placeholder="Amount" @bind="newItemAmount" />
                        </div>
                        <div class="col-md-3">
                            <button class="btn btn-success" @onclick="AddItemAsync">Add Item</button>
                        </div>
                    </div>
                </div>
            </div>
        </div>

        <div class="col-md-4">
            <div class="card">
                <div class="card-header">Process Payment</div>
                <div class="card-body">
                    <p>Balance: <strong>@invoice.Balance.ToString("C")</strong></p>
                    @if (invoice.Balance > 0)
                    {
                        <div class="mb-2">
                            <label class="form-label">Amount</label>
                            <input type="number" step="0.01" class="form-control" @bind="paymentAmount" />
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Method</label>
                            <select class="form-select" @bind="paymentMethod">
                                @foreach (var m in Enum.GetValues<VetClinic.Data.Models.PaymentMethod>())
                                {
                                    <option value="@m">@m</option>
                                }
                            </select>
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Reference</label>
                            <input class="form-control" @bind="paymentReference" />
                        </div>
                        <button class="btn btn-primary w-100" @onclick="ProcessPaymentAsync">Process Payment</button>
                    }
                    else
                    {
                        <p class="text-success"><strong>Fully Paid</strong></p>
                    }
                </div>
            </div>

            @if (invoice.Payments.Any())
            {
                <div class="card mt-3">
                    <div class="card-header">Payments</div>
                    <ul class="list-group list-group-flush">
                        @foreach (var p in invoice.Payments)
                        {
                            <li class="list-group-item">
                                @p.PaidAt.ToString("g") — @p.Amount.ToString("C") (@p.Method)
                            </li>
                        }
                    </ul>
                </div>
            }
        </div>
    </div>

    <a href="billing" class="btn btn-secondary mt-3">Back to Billing</a>
}

@code {
    [Parameter] public int? InvoiceId { get; set; }

    private VetClinic.Data.Models.Invoice invoice = new() { DueDate = DateTime.Today.AddDays(30) };
    private List<VetClinic.Data.Models.Owner> owners = [];

    private string newItemDescription = string.Empty;
    private decimal newItemAmount;
    private decimal paymentAmount;
    private VetClinic.Data.Models.PaymentMethod paymentMethod;
    private string? paymentReference;

    protected override async Task OnInitializedAsync()
    {
        owners = await PatientSvc.GetOwnersAsync();
        if (InvoiceId.HasValue)
        {
            var loaded = await BillingSvc.GetInvoiceAsync(InvoiceId.Value);
            if (loaded != null) invoice = loaded;
            paymentAmount = invoice.Balance;
        }
    }

    private async Task CreateInvoiceAsync()
    {
        if (invoice.OwnerId == 0) return;
        await BillingSvc.SaveInvoiceAsync(invoice);
        Nav.NavigateTo($"billing/{invoice.Id}");
    }

    private async Task AddItemAsync()
    {
        if (string.IsNullOrWhiteSpace(newItemDescription) || newItemAmount <= 0) return;
        await BillingSvc.AddLineItemAsync(invoice.Id, newItemDescription, newItemAmount);
        newItemDescription = string.Empty;
        newItemAmount = 0;
        await ReloadAsync();
    }

    private async Task RemoveItemAsync(int itemId)
    {
        await BillingSvc.RemoveLineItemAsync(itemId);
        await ReloadAsync();
    }

    private async Task ProcessPaymentAsync()
    {
        if (paymentAmount <= 0) return;
        await BillingSvc.ProcessPaymentAsync(invoice.Id, paymentAmount, paymentMethod, paymentReference);
        paymentReference = null;
        await ReloadAsync();
        paymentAmount = invoice.Balance;
    }

    private async Task ReloadAsync()
    {
        var loaded = await BillingSvc.GetInvoiceAsync(invoice.Id);
        if (loaded != null) invoice = loaded;
    }

    private string StatusBadge(VetClinic.Data.Models.InvoiceStatus status) => status switch
    {
        VetClinic.Data.Models.InvoiceStatus.Pending => "bg-warning text-dark",
        VetClinic.Data.Models.InvoiceStatus.Paid => "bg-success",
        VetClinic.Data.Models.InvoiceStatus.Overdue => "bg-danger",
        _ => "bg-secondary"
    };
}
