        editingAppointment.EndTime = editingAppointment.StartTime.AddMinutes(durationMinutes);
        await AppointmentSvc.SaveAppointmentAsync(editingAppointment);
        ResetForm();
        await LoadWeekAsync();
    }

    private async Task CancelAppointment()
    {
        if (editingAppointment.Id > 0)
        {
            await AppointmentSvc.CancelAppointmentAsync(editingAppointment.Id);
            ResetForm();
            await LoadWeekAsync();
        }
    }

    private void ResetForm()
    {
        editingAppointment = new VetClinic.Data.Models.Appointment { StartTime = DateTime.Today.AddHours(9) };
        durationMinutes = 30;
    }
}

